  ('social-worker-moex-02775', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '民國102年7月23日衛生福利部正式成立，原由內政部主管之社會司、兒童局、家庭暴力及性侵害防治 委員會等相關社福單位業務進行調整，下列敘述何者錯誤？', '["整併原社會司社會救助、社會保險、社區及少年福利業務，成立「社會救助及社工司」", "社會團體科、職業團體科、合作事業輔導科及合作行政管理科續留內政部，並成立「合作及人民團體 司」", "原社會司老人、婦女、身心障礙者等族群福利服務，與兒童局之兒童、少年福利業務整併，成立「社 會及家庭署」", "原家庭暴力及性侵害防治委員會業務，與兒童局保護重建及防制輔導相關業務整併，成立「保護服務 司」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "944ac06427af", "answer_pdf_sha1": "e152c78dc639", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
